import{j as e}from"./index-CIDTK77q.js";const t={getCompanies:async()=>(await e.get(`/crm/companies`)).data,getCompanyById:async t=>(await e.get(`/crm/companies/${t}`)).data,getCompanyInsights:async t=>(await e.get(`/crm/companies/${t}/insights`)).data,createCompany:async t=>(await e.post(`/crm/companies`,t)).data,updateCompany:async(t,n)=>(await e.patch(`/crm/companies/${t}`,n)).data,enrichCompany:async t=>(await e.post(`/crm/companies/${t}/enrich`)).data,bulkEnrich:async t=>(await e.post(`/crm/companies/bulk-enrich`,{ids:t})).data};export{t};